import{_ as a,o as i,c as o,ag as l}from"./chunks/framework.DTiDeF2Q.js";const z=JSON.parse('{"title":"Aliasy Dig | Dotfiles (PL)","titleTemplate":":title","description":"Skrocone polecenia zapytan DNS. Przeglad dla Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","frontmatter":{"title":"Aliasy Dig | Dotfiles","description":"Skrocone polecenia zapytan DNS. Przeglad dla Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","lang":"pl-PL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasy Dig | Dotfiles preview","canonical":"/pl/aliases/dig/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasy Dig","pageType":"docs","schemaType":"WebPage","permalink":"/pl/aliases/dig/"},"headers":[],"relativePath":"pl/aliases/dig/index.md","filePath":"pl/aliases/dig/index.md","lastUpdated":1773010926000}'),d={name:"pl/aliases/dig/index.md"};function n(t,e,c,r,s,p){return i(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="aliasy-dig" tabindex="-1">Aliasy Dig <a class="header-anchor" href="#aliasy-dig" aria-label="Permalink to &quot;Aliasy Dig&quot;">​</a></h1><p>Skrocone polecenia zapytan DNS.</p><p>Ta strona przedstawia jedna grupe aliasow i jej typowe skroty polecen. Przeczytaj ja najpierw, aby zrozumiec konwencje nazewnictwa, oczekiwane dane wejsciowe i bezpieczne wzorce wykonywania. Nastepnie otworz dodatek referencyjny, aby zobaczyc pelny spis polecen i dokladna skladnie. Te aliasy redukuja powtarzalne wpisywanie i zapewniaja spojne zachowanie przeplywy pracy na macOS, Linux i WSL.</p><h2 id="kiedy-uzywac" tabindex="-1">Kiedy uzywac <a class="header-anchor" href="#kiedy-uzywac" aria-label="Permalink to &quot;Kiedy uzywac&quot;">​</a></h2><p>Uzyj tej strony przed codziennym uzywaniem powloki, gdy potrzebujesz przewidywalnych wzorcow polecen.</p><h2 id="co-zawiera" tabindex="-1">Co zawiera <a class="header-anchor" href="#co-zawiera" aria-label="Permalink to &quot;Co zawiera&quot;">​</a></h2><ul><li>Aliasy: 10</li><li>Funkcje pomocnicze: 0</li><li>Pliki zrodlowe: 1</li></ul><h2 id="szybkie-przyklady" tabindex="-1">Szybkie przyklady <a class="header-anchor" href="#szybkie-przyklady" aria-label="Permalink to &quot;Szybkie przyklady&quot;">​</a></h2><ul><li><code>d</code> -&gt; <code>dig</code></li><li><code>d4</code> -&gt; <code>dig +short -4</code></li><li><code>d6</code> -&gt; <code>dig +short -6</code></li><li><code>dga</code> -&gt; <code>dig +all ANY</code></li><li><code>dgs</code> -&gt; <code>dig +short</code></li><li><code>digg</code> -&gt; <code>dig @8.8.8.8 +nocmd any +multiline +noall +answer</code></li><li><code>ip4</code> -&gt; <code>dig +short myip.opendns.com @resolver1.opendns.com -4</code></li><li><code>ip6</code> -&gt; <code>dig -6 AAAA +short myip.opendns.com. @resolver1.opendns.com.</code></li><li><code>ips</code> -&gt; <code>ip4; ip6</code></li><li><code>wip</code> -&gt; <code>dig +short myip.opendns.com @resolver1.opendns.com</code></li></ul><h2 id="nastepny-krok" tabindex="-1">Nastepny krok <a class="header-anchor" href="#nastepny-krok" aria-label="Permalink to &quot;Nastepny krok&quot;">​</a></h2><p>Otworz pelna liste:</p>',11)])])}const g=a(d,[["render",n]]);export{z as __pageData,g as default};
